# === helper _overlaps_any (app/ai/stages.py) ===
def _overlaps_any(span, spans):
    start, end = span
    return any(start < other_end and end > other_start for other_start, other_end in spans)


# === helper _target_date_from_text (app/ai/stages.py) ===
def _target_date_from_text(text, now):
    if "day after tomorrow" in text:
        return (now + timedelta(days=2)).date()
    if "tomorrow" in text:
        return (now + timedelta(days=1)).date()
    if "today" in text:
        return now.date()

    for match in NUMERIC_DATE_PATTERN.finditer(text):
        day = int(match.group(1))
        month = int(match.group(2))
        year_text = match.group(3)
        year = now.year
        if year_text:
            year = int(year_text)
            if year < 100:
                year += 2000
        try:
            candidate = datetime(year, month, day).date()
        except ValueError:
            continue
        if candidate < now.date() and not year_text:
            try:
                candidate = datetime(year + 1, month, day).date()
            except ValueError:
                continue
        return candidate

    weekdays = {
        "monday": 0,
        "tuesday": 1,
        "wednesday": 2,
        "thursday": 3,
        "friday": 4,
        "saturday": 5,
        "sunday": 6,
    }
    for name, index in weekdays.items():
        if name in text:
            days_ahead = (index - now.weekday()) % 7
            if days_ahead == 0:
                days_ahead = 7
            return (now + timedelta(days=days_ahead)).date()

    return now.date()

